-- FSI_DEMO_DB.CAPITAL_MARKETS.RESEARCH_NOTES

CREATE OR REPLACE TABLE FSI_DEMO_DB.CAPITAL_MARKETS.RESEARCH_NOTES (

    NOTE_ID VARCHAR(20) NOT NULL,
    SECURITY_ID VARCHAR(20),
    ANALYST_ID VARCHAR(20),
    ANALYST_NAME VARCHAR(100),
    PUBLISH_DATE DATE,
    REPORT_TYPE VARCHAR(50),
    TITLE VARCHAR(300),
    CONTENT VARCHAR(16777216),
    RECOMMENDATION VARCHAR(30),
    TARGET_PRICE NUMBER(18,4),
    PREVIOUS_TARGET NUMBER(18,4),
    RATING_CHANGE VARCHAR(30),
    KEY_POINTS VARCHAR(16777216),
    RISKS VARCHAR(16777216),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (NOTE_ID)

);

